}

function Component({ props }) {
  const _th = props._th || {};
  return (
    <>
      <style>{`
.pc-md{width:100%;max-height:100%;overflow:auto;box-sizing:border-box;padding:8px;
 font-family:system-ui,-apple-system,sans-serif;font-size:13px;line-height:1.5;
 color:var(--pc-text)}
.pc-md h1,.pc-md h2,.pc-md h3{margin:.4em 0 .3em;line-height:1.25}
.pc-md h1{font-size:1.5em}.pc-md h2{font-size:1.3em}.pc-md h3{font-size:1.1em}
.pc-md p{margin:.4em 0}.pc-md ul,.pc-md ol{margin:.4em 0;padding-left:1.4em}
.pc-md a{color:var(--pc-accent)}
.pc-md img{display:block;max-width:100%}
.pc-md pre{background:var(--pc-code-bg);border-radius:6px;padding:8px;overflow:auto}
.pc-md code{background:var(--pc-code-bg);border-radius:4px;padding:1px 4px;
 font-family:ui-monospace,SFMono-Regular,Menlo,monospace;font-size:12px}
.pc-md pre code{background:none;padding:0}
.pc-md table{border-collapse:collapse}
.pc-md th,.pc-md td{border:1px solid var(--pc-border);padding:3px 8px}
`}</style>
      <div className="pc-md" style={_th}
           dangerouslySetInnerHTML={{ __html: props.html || "" }} />
    </>
  );
}

function Component({ canvas, value, props }) {
  const initial = value != null ? value
                : (props.value != null ? props.value : props.default);
  const [v, setV] = React.useState(initial);
  const [raw, setRaw] = React.useState(null);
  React.useEffect(() => { if (value != null) setV(value); }, [value]);
  const onRelease = props.on_release;
  const lo = Number(props.min), hi = Number(props.max), st = Number(props.step);
  const isFloat = String(props.step).indexOf(".") >= 0;
  const show = isFloat ? Number(v).toFixed(2) : String(v);

  function commit() {
    if (raw === null) return;
    const parsed = parseFloat(raw);
    const clamped = isNaN(parsed) ? v : Math.max(lo, Math.min(hi, parsed));
    const snapped = Math.round((clamped - lo) / st) * st + lo;
    const clean = Math.round(snapped * 1e10) / 1e10;
    setV(clean);
    setRaw(null);
    canvas.send({ value: clean });
  }

  const _th = props._th || {};
  return (
    <>
      <style>{`
.pc-slider{box-sizing:border-box;width:100%;height:100%;padding:10px 12px;
 display:flex;gap:10px;align-items:center;
 font:600 12px system-ui,-apple-system,sans-serif;color:var(--pc-text,#e6edf3)}
.pc-slider input[type=range]{flex:1;min-width:0;accent-color:var(--pc-accent,#3b82f6)}
.pc-slider .val{width:5ch;text-align:center;font-variant-numeric:tabular-nums;
 background:none;border:none;border-bottom:1px solid transparent;color:inherit;
 font:inherit;padding:0;cursor:text;outline:none}
.pc-slider .val:hover{border-bottom-color:rgba(255,255,255,.25)}
.pc-slider .val:focus{border-bottom-color:var(--pc-accent,#3b82f6);
 box-shadow:0 2px 0 var(--pc-accent-t,rgba(59,130,246,.3))}
`}</style>
      <div className="pc-slider" style={_th}>
        <input type="range" min={props.min} max={props.max} step={props.step}
          value={v}
          onPointerDown={(e) => { try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {} }}
          onChange={(e) => {
            const n = Number(e.target.value);
            setV(n);
            if (!onRelease) canvas.send({ value: n });
          }}
          onPointerUp={onRelease
            ? (e) => canvas.send({ value: Number(e.target.value) })
            : undefined} />
        <input className="val"
          type="text"
          inputMode={isFloat ? "decimal" : "numeric"}
          value={raw !== null ? raw : show}
          onFocus={(e) => { setRaw(show); const t = e.target; requestAnimationFrame(() => t.select()); }}
          onChange={(e) => setRaw(e.target.value)}
          onBlur={commit}
          onKeyDown={(e) => {
            if (e.key === "Enter") { e.target.blur(); return; }
            if (e.key === "ArrowUp" || e.key === "ArrowDown") {
              e.preventDefault();
              const delta = e.key === "ArrowUp" ? st : -st;
              const clamped = Math.max(lo, Math.min(hi, v + delta));
              const snapped = Math.round((clamped - lo) / st) * st + lo;
              const clean = Math.round(snapped * 1e10) / 1e10;
              setV(clean); setRaw(null); canvas.send({ value: clean });
            }
          }} />
      </div>
    </>
  );
}

function Component({ canvas, value, props }) {
  const initial = value != null ? value : (props.value != null ? props.value : "");
  const [text, setText] = React.useState(initial);
  React.useEffect(() => { if (value != null) setText(value); }, [value]);
  function commit(v) { canvas.send({ value: v }); }
  const _th = props._th || {};
  if (props.multiline) {
    return (
      <>
        <style>{`
.pc-field{box-sizing:border-box;width:100%;height:100%;padding:10px 12px;
 display:flex;align-items:stretch}
.pc-field input,.pc-field textarea{flex:1;min-height:0;min-width:0;
 box-sizing:border-box;padding:6px 8px;
 background:var(--pc-input-bg,#ffffff);border:1px solid var(--pc-border,#e2e2e2);
 border-radius:6px;color:var(--pc-text,#e6edf3);
 font:13px system-ui,-apple-system,sans-serif;resize:none;outline:none}
.pc-field input:focus,.pc-field textarea:focus{
 border-color:var(--pc-accent,#3b82f6);
 box-shadow:0 0 0 3px var(--pc-accent-t,rgba(59,130,246,.25))}
.pc-field textarea{resize:vertical}
`}</style>
        <div className="pc-field" style={_th}>
          <textarea placeholder={props.placeholder || ""}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onBlur={(e) => commit(e.target.value)} />
        </div>
      </>
    );
  }
  return (
    <>
      <style>{`
.pc-field{box-sizing:border-box;width:100%;height:100%;padding:10px 12px;
 display:flex;align-items:stretch}
.pc-field input,.pc-field textarea{flex:1;min-height:0;min-width:0;
 box-sizing:border-box;padding:6px 8px;
 background:var(--pc-input-bg,#ffffff);border:1px solid var(--pc-border,#e2e2e2);
 border-radius:6px;color:var(--pc-text,#e6edf3);
 font:13px system-ui,-apple-system,sans-serif;resize:none;outline:none}
.pc-field input:focus,.pc-field textarea:focus{
 border-color:var(--pc-accent,#3b82f6);
 box-shadow:0 0 0 3px var(--pc-accent-t,rgba(59,130,246,.25))}
.pc-field textarea{resize:vertical}
`}</style>
      <div className="pc-field" style={_th}>
        <input type="text" placeholder={props.placeholder || ""}
          value={text}
          onChange={(e) => setText(e.target.value)}
          onBlur={(e) => commit(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") { commit(e.target.value); e.target.blur(); }
          }} />
      </div>
    </>
  );
}

function Component({ canvas, value, props }) {
  const initial = value != null ? value
                : (props.value != null ? props.value : props.options[0]);
  const [sel, setSel] = React.useState(initial);
  React.useEffect(() => { if (value != null) setSel(value); }, [value]);
  const _th = props._th || {};
  return (
    <>
      <style>{`
.pc-toggle{box-sizing:border-box;width:100%;height:100%;padding:10px 12px;
 display:flex;gap:6px;align-items:center;flex-wrap:wrap}
.pc-toggle button{flex:1;min-width:0;padding:7px 10px;cursor:pointer;
 font:600 12px system-ui,-apple-system,sans-serif;color:var(--pc-off-text,#333333);
 background:var(--pc-off-bg,#eeeeee);border:1px solid var(--pc-border,#30363d);
 border-radius:7px;transition:background .12s}
.pc-toggle button.sel{background:var(--pc-accent,#3b82f6);border-color:transparent;
 color:var(--pc-accent-text,#fff)}
`}</style>
      <div className="pc-toggle" style={_th}>
        {props.options.map((opt) => (
          <button key={opt}
            className={opt === sel ? "sel" : ""}
            onClick={() => { setSel(opt); canvas.send({ value: opt }); }}>
            {opt}
          </button>
        ))}
      </div>
    </>
  );
}
